  tools.shell_command({
    command: "set -euo pipefail\npwd\ngit status --short --branch\nprintf '\\n--- ralplan state ---\\n'\nif [ -f .omx/state/sessions/omx-1777311520377-ztpj7r/ralplan-state.json ]; then cat .omx/state/sessions/omx-1777311520377-ztpj7r/ralplan-state.json; else echo 'missing'; fi\nprintf '\\n--- relevant artifacts ---\\n'\nfind .omx/artifacts -maxdepth 1 -type f \\( -name 'claude-*review*.md' -o -name 'claude-strict-codebase-review-*.md' \\) -print | sort | tail -10",
