   258	
   259	// tableRelation represents a table and its parent table name (empty if root).
   260	type tableRelation struct {
   261		name   string
   262		parent string
   263	}
   264	
   265	// topologicalSort sorts tables so that child tables come before parent tables.
   266	// This ensures that DELETE operations respect foreign key / interleave constraints.
   267	func topologicalSort(tables []tableRelation) []string {
   268		// Build a map of parent -> children.
   269		children := make(map[string][]string)
   270		var roots []string
   271	
   272		for _, t := range tables {
   273			if t.parent == "" {
   274				roots = append(roots, t.name)
   275			} else {
   276				children[t.parent] = append(children[t.parent], t.name)
   277			}
   278		}
   279	
   280		// DFS post-order: children before parents.
   281		var result []string
   282		visited := make(map[string]bool)
   283		var visit func(name string)
   284		visit = func(name string) {
   285			if visited[name] {
   286				return
   287			}
   288			visited[name] = true
   289			for _, child := range children[name] {
   290				visit(child)
   291			}
   292			result = append(result, name)
   293		}
   294	
   295		for _, root := range roots {
   296			visit(root)
   297		}
   298	
   299		// Add any orphan tables not reachable from roots.
   300		for _, t := range tables {
   301			if !visited[t.name] {
   302				visit(t.name)
   303			}
   304		}
   305	
   306		return result
   307	}

