    27	
    28	// Executor handles migration execution and version tracking.
    29	type Executor struct {
    30		client *spannerutil.Client
    31	}
    32	
    33	// NewExecutor creates a new migration executor.
    34	func NewExecutor(client *spannerutil.Client) *Executor {
    35		return &Executor{client: client}
    36	}
    37	
    38	// EnsureTable creates the SchemaMigrations table if it does not exist.
    39	func (e *Executor) EnsureTable(ctx context.Context) error {
    40		// Try to query the table; if it fails, create it.
    41		iter := e.client.Single().Query(ctx, spanner.Statement{
    42			SQL: "SELECT Version FROM SchemaMigrations LIMIT 1",
    43		})
    44		if err := iter.Do(func(_ *spanner.Row) error { return nil }); err != nil {
    45			if spanner.ErrCode(err) == codes.NotFound || isTableNotFoundError(err) {
    46				return e.client.UpdateDatabaseDDL(ctx, []string{SchemaMigrationsTableDDL})
    47			}
    48			return fmt.Errorf("checking SchemaMigrations table: %w", err)
    49		}
    50		return nil
    51	}
    52	
    53	// GetVersion returns the current migration version and dirty flag.
    54	func (e *Executor) GetVersion(ctx context.Context) (version uint, dirty bool, err error) {
    55		iter := e.client.Single().Query(ctx, spanner.Statement{
    56			SQL: "SELECT Version, Dirty FROM SchemaMigrations ORDER BY Version DESC LIMIT 1",
    57		})
    58	
    59		var found bool
    60		if err := iter.Do(func(row *spanner.Row) error {
    61			var v int64
    62			var d bool
    63			if err := row.Columns(&v, &d); err != nil {
    64				return err
    65			}
    66			version = uint(v)
    67			dirty = d
    68			found = true
    69			return nil
    70		}); err != nil {
    71			return 0, false, fmt.Errorf("querying migration version: %w", err)
    72		}
    73	
    74		if !found {
    75			return 0, false, nil
    76		}
    77	
    78		return version, dirty, nil
    79	}
    80	
    81	// SetVersion sets the migration version and dirty flag.
    82	func (e *Executor) SetVersion(ctx context.Context, version uint, dirty bool) error {
    83		return e.client.ReadWriteTransaction(ctx, func(ctx context.Context, txn *spanner.ReadWriteTransaction) error {
    84			// Delete all existing rows.
    85			if _, err := txn.Update(ctx, spanner.Statement{SQL: "DELETE FROM SchemaMigrations WHERE true"}); err != nil {
    86				return err
    87			}
    88			// Insert the new version.
    89			m := []*spanner.Mutation{
    90				spanner.InsertOrUpdate("SchemaMigrations",
    91					[]string{"Version", "Dirty"},
    92					[]any{int64(version), dirty},
    93				),
    94			}
    95			return txn.BufferWrite(m)
    96		})
    97	}
    98	
    99	// ExecuteMigrations applies pending migrations sequentially.
   100	// It returns the number of migrations applied.
   101	// If limit is 0, all pending migrations are applied.
   102	func (e *Executor) ExecuteMigrations(ctx context.Context, migrations []Migration, limit int) (int, error) {
   103		currentVersion, dirty, err := e.GetVersion(ctx)
   104		if err != nil {
   105			return 0, err
   106		}
   107	
   108		if dirty {
   109			return 0, fmt.Errorf("database is dirty at version %d; fix the issue and use 'migrate set' to reset the dirty flag", currentVersion)
   110		}
   111	
   112		applied := 0
   113		for _, m := range migrations {
   114			if m.Version <= currentVersion {
   115				continue
   116			}
   117			if limit > 0 && applied >= limit {
   118				break
   119			}
   120	
   121			// Set dirty flag.
   122			if err := e.SetVersion(ctx, m.Version, true); err != nil {
   123				return applied, fmt.Errorf("setting dirty flag for version %d: %w", m.Version, err)
   124			}
   125	
   126			// Execute statements.
   127			switch m.Kind {
   128			case sqlutil.KindDDL:
   129				if err := e.client.UpdateDatabaseDDL(ctx, m.Statements); err != nil {
   130					return applied, fmt.Errorf("executing DDL migration %d (%s): %w", m.Version, m.Name, err)
   131				}
   132			case sqlutil.KindDML:
   133				if err := e.client.ApplyDML(ctx, m.Statements); err != nil {
   134					return applied, fmt.Errorf("executing DML migration %d (%s): %w", m.Version, m.Name, err)
   135				}
   136			case sqlutil.KindPartitionedDML:
   137				for _, stmt := range m.Statements {
   138					if _, err := e.client.ApplyPartitionedDML(ctx, stmt); err != nil {
   139						return applied, fmt.Errorf("executing partitioned DML migration %d (%s): %w", m.Version, m.Name, err)
   140					}
   141				}
   142			}
   143	
   144			// Clear dirty flag.
   145			if err := e.SetVersion(ctx, m.Version, false); err != nil {
   146				return applied, fmt.Errorf("clearing dirty flag for version %d: %w", m.Version, err)
   147			}
   148	
   149			applied++
   150		}
   151	
   152		return applied, nil
   153	}
   154	
   155	// isTableNotFoundError checks if the error indicates a table was not found.
   156	func isTableNotFoundError(err error) bool {
   157		if err == nil {
   158			return false
   159		}
   160		// Spanner returns INVALID_ARGUMENT when querying a non-existent table.
   161		return spanner.ErrCode(err) == codes.InvalidArgument
   162	}

