    15	// Package migration implements versioned schema migration management for Cloud Spanner.
    16	package migration
    17	
    18	import (
    19		"fmt"
    20		"os"
    21		"path/filepath"
    22		"regexp"
    23		"sort"
    24		"strconv"
    25	
    26		"github.com/zchee/spanner-manager/sqlutil"
    27	)
    28	
    29	// Migration represents a single versioned migration file.
    30	type Migration struct {
    31		// Version is the migration version number.
    32		Version uint
    33	
    34		// Name is the human-readable migration name.
    35		Name string
    36	
    37		// Statements are the SQL statements to execute.
    38		Statements []string
    39	
    40		// Kind is the type of statements (DDL, DML, or PartitionedDML).
    41		Kind sqlutil.StatementKind
    42	}
    43	
    44	// migrationFilePattern matches migration filenames like "000001_add_users_table.sql".
    45	var migrationFilePattern = regexp.MustCompile(`^([0-9]+)(?:_([a-zA-Z0-9_\-]+))?(\.up)?\.sql$`)
    46	
    47	// ReadMigrations reads and parses all migration files from the migrations/ subdirectory.
    48	// Files must match the pattern: {VERSION}_{NAME}.sql or {VERSION}_{NAME}.up.sql.
    49	func ReadMigrations(dir string) ([]Migration, error) {
    50		migrationsDir := filepath.Join(dir, "migrations")
    51	
    52		entries, err := os.ReadDir(migrationsDir)
    53		if err != nil {
    54			return nil, fmt.Errorf("reading migrations directory: %w", err)
    55		}
    56	
    57		var migrations []Migration
    58		for _, entry := range entries {
    59			if entry.IsDir() {
    60				continue
    61			}
    62	
    63			matches := migrationFilePattern.FindStringSubmatch(entry.Name())
    64			if matches == nil {
    65				continue
    66			}
    67	
    68			version, err := strconv.ParseUint(matches[1], 10, 64)
    69			if err != nil {
    70				return nil, fmt.Errorf("parsing version from %s: %w", entry.Name(), err)
    71			}
    72	
    73			name := matches[2]
    74	
    75			data, err := os.ReadFile(filepath.Join(migrationsDir, entry.Name()))
    76			if err != nil {
    77				return nil, fmt.Errorf("reading migration file %s: %w", entry.Name(), err)
    78			}
    79	
    80			stmts, err := sqlutil.SplitStatements(string(data))
    81			if err != nil {
    82				return nil, fmt.Errorf("parsing migration file %s: %w", entry.Name(), err)
    83			}
    84	
    85			if len(stmts) == 0 {
    86				continue
    87			}
    88	
    89			// Classify statements — all must be the same kind.
    90			kind, err := sqlutil.ClassifyStatement(stmts[0])
    91			if err != nil {
    92				return nil, fmt.Errorf("classifying statement in %s: %w", entry.Name(), err)
    93			}
    94	
    95			for i := 1; i < len(stmts); i++ {
    96				k, err := sqlutil.ClassifyStatement(stmts[i])
    97				if err != nil {
    98					return nil, fmt.Errorf("classifying statement %d in %s: %w", i+1, entry.Name(), err)
    99				}
   100				if k != kind {
   101					return nil, fmt.Errorf("mixed statement kinds in %s: statement 1 is %s but statement %d is %s", entry.Name(), kind, i+1, k)
   102				}
   103			}
   104	
   105			migrations = append(migrations, Migration{
   106				Version:    uint(version),
   107				Name:       name,
   108				Statements: stmts,
   109				Kind:       kind,
