await tools.update_plan({
  explanation: "Task ownership is stable; monitoring until task 3 and task 4 reach terminal state.",
  plan: [
    {step: "Preflight tmux, omx, HUD panes, branch/worktree, and planning artifacts", status: "completed"},
    {step: "Launch 4-worker OMX team with lane ownership from ralplan plan", status: "completed"},
    {step: "Verify team startup: team name, panes, state files, ACK/mailbox evidence", status: "completed"},
    {step: "Correct task ownership so workers 1-4 map to lanes 1-4", status: "completed"},
    {step: "Monitor team runtime status until tasks are terminal", status: "in_progress"},
    {step: "Integrate or inspect worker commits/results by concern", status: "pending"},
    {step: "Run required verification bundle from plan", status: "pending"},
    {step: "Shutdown team only after pending/in_progress/failed are clear or explicitly handled", status: "pending"},
    {step: "Report changed files, commands, evidence, commits, and risks", status: "pending"}
  ]
});
const cwd = "/Users/zchee/go/src/github.com/zchee/spanner-manager";
const team = "execute-omx-plans-ralplan-fix";
const out = await tools.shell_command({
  command: `set -euo pipefail
team="${team}"
printf '%s\\n' '--- await 30s ---'
omx team await "$team" --timeout-ms 30000 --json || true
printf '%s\\n' ''
printf '%s\\n' '--- status after await ---'
omx team status "$team" --json --tail-lines 200 || true
printf '%s\\n' ''
printf '%s\\n' '--- tasks after await ---'
omx team api list-tasks --input '{"team_name":"'"$team"'"}' --json || true
printf '%s\\n' ''
printf '%s\\n' '--- mailbox tail ---'
python3 - <<'PY'
import json, pathlib
p=pathlib.Path(".omx/state/team/execute-omx-plans-ralplan-fix/mailbox/leader-fixed.json")
d=json.loads(p.read_text())
for m in d.get("messages", [])[-10:]:
    print(f"{m['created_at']} {m['from_worker']}: {m['body']}")
PY`,
  workdir: cwd,
  timeout_ms: 45000
});
text(out);

