 	if err != nil {
 		adminClient.Close()
 		instanceClient.Close()
 		return nil, fmt.Errorf("creating spanner data client: %w", err)
 	}

 	return &Client{
 		config:   cfg,
 		admin:    adminClient,
 		instance: instanceClient,
 		data:     dataClient,
 	}, nil
 }

